//! UCAN admission management — list/add/edit/revoke the binaries monster-guard
//! will run, and the capabilities (fs/net/exec) each is granted.
//!
//! There is no `monster-guard list`, so listing reads `$GUARD_HOME/grants/*.ucan`
//! and decodes each UCAN's payload (base64url JWT segment 1) for the plugin name,
//! caps, and expiry. Mutations shell out to `monster-guard delegate` / `revoke`.

use serde::Serialize;
use std::process::Command;

/// One admitted binary/plugin and its current grant.
#[derive(Debug, Clone, Serialize)]
pub struct Admission {
    pub name: String,
    pub caps: Vec<String>,
    /// Unix seconds; None if the grant couldn't be decoded.
    pub expires_at: Option<i64>,
    /// True if expiry is in the past (best-effort; uses provided `now`).
    pub expired: bool,
    /// True if this grant's jti/token appears in revocations.json.
    pub revoked: bool,
}

fn guard_bin() -> Result<String, String> {
    if let Ok(b) = std::env::var("MONSTER_GUARD_BIN") {
        return Ok(b);
    }
    which::which("monster-guard")
        .map(|p| p.to_string_lossy().to_string())
        .map_err(|_| "monster-guard not found; set MONSTER_GUARD_BIN".to_string())
}

fn guard_home() -> String {
    std::env::var("MONSTER_GUARD_HOME").unwrap_or_else(|_| {
        home::home_dir()
            .map(|h| h.join(".moonshine.d").to_string_lossy().to_string())
            .unwrap_or_else(|| ".moonshine.d".to_string())
    })
}

/// Minimal base64url (no-pad) decoder, so we don't pull in the base64 crate
/// (which would require an `a0 summon`). Returns None on any invalid input.
fn b64url_decode(s: &str) -> Option<Vec<u8>> {
    fn val(c: u8) -> Option<u8> {
        match c {
            b'A'..=b'Z' => Some(c - b'A'),
            b'a'..=b'z' => Some(c - b'a' + 26),
            b'0'..=b'9' => Some(c - b'0' + 52),
            b'-' => Some(62),
            b'_' => Some(63),
            _ => None,
        }
    }
    let bytes = s.as_bytes();
    let mut out = Vec::with_capacity(bytes.len() * 3 / 4);
    let mut acc: u32 = 0;
    let mut nbits = 0u32;
    for &c in bytes {
        let v = val(c)? as u32;
        acc = (acc << 6) | v;
        nbits += 6;
        if nbits >= 8 {
            nbits -= 8;
            out.push((acc >> nbits) as u8);
        }
    }
    Some(out)
}

/// Decode the payload (segment 1) of a UCAN JWT to JSON.
fn decode_payload(token: &str) -> Option<serde_json::Value> {
    let seg = token.trim().split('.').nth(1)?;
    let bytes = b64url_decode(seg)?;
    serde_json::from_slice(&bytes).ok()
}

/// Read revocations.json into (token_hash jti set) for marking revoked grants.
fn load_revoked_jtis(home: &str) -> std::collections::HashSet<String> {
    let mut set = std::collections::HashSet::new();
    if let Ok(s) = std::fs::read_to_string(format!("{}/revocations.json", home)) {
        if let Ok(v) = serde_json::from_str::<serde_json::Value>(&s) {
            if let Some(arr) = v.get("jti").and_then(|x| x.as_array()) {
                for j in arr {
                    if let Some(s) = j.as_str() {
                        set.insert(s.to_string());
                    }
                }
            }
        }
    }
    set
}

/// List all admitted plugins by reading the grants directory.
pub fn list_admissions(now_secs: i64) -> Result<Vec<Admission>, String> {
    let home = guard_home();
    let dir = format!("{}/grants", home);
    let revoked = load_revoked_jtis(&home);

    let rd = match std::fs::read_dir(&dir) {
        Ok(rd) => rd,
        Err(_) => return Ok(Vec::new()), // no grants yet
    };

    let mut out = Vec::new();
    for entry in rd.flatten() {
        let path = entry.path();
        if path.extension().and_then(|e| e.to_str()) != Some("ucan") {
            continue;
        }
        let name = path
            .file_stem()
            .and_then(|n| n.to_str())
            .unwrap_or("(unknown)")
            .to_string();
        let token = match std::fs::read_to_string(&path) {
            Ok(t) => t,
            Err(_) => continue,
        };
        let payload = decode_payload(&token);
        let (caps, expires_at, jti) = payload
            .as_ref()
            .map(|p| {
                let caps = p["att"][0]["constraints"]["caps"]
                    .as_array()
                    .map(|a| {
                        a.iter()
                            .filter_map(|c| c.as_str().map(String::from))
                            .collect::<Vec<_>>()
                    })
                    .unwrap_or_default();
                let exp = p["exp"].as_i64();
                let jti = p["jti"].as_str().unwrap_or("").to_string();
                (caps, exp, jti)
            })
            .unwrap_or((Vec::new(), None, String::new()));

        out.push(Admission {
            name,
            caps,
            expires_at,
            expired: expires_at.map(|e| e < now_secs).unwrap_or(false),
            revoked: !jti.is_empty() && revoked.contains(&jti),
        });
    }
    out.sort_by(|a, b| a.name.cmp(&b.name));
    Ok(out)
}

/// Admit (or re-admit) a plugin with the given caps and ttl.
pub fn delegate(name: &str, caps: &[String], ttl_secs: i64) -> Result<String, String> {
    if name.is_empty() || name.contains('/') || name.contains("..") {
        return Err("invalid plugin name".into());
    }
    let caps_arg = if caps.is_empty() { "-".to_string() } else { caps.join(",") };
    let out = Command::new(guard_bin()?)
        .env("MONSTER_GUARD_HOME", guard_home())
        .args(["delegate", name, &caps_arg, "--ttl", &ttl_secs.to_string()])
        .output()
        .map_err(|e| format!("spawn monster-guard: {e}"))?;
    if out.status.success() {
        Ok(String::from_utf8_lossy(&out.stdout).trim().to_string())
    } else {
        Err(String::from_utf8_lossy(&out.stderr).trim().to_string())
    }
}

/// Revoke (lock down) a plugin's command grant. Running invocations die at the
/// next lease tick; future runs are denied.
pub fn revoke(name: &str) -> Result<String, String> {
    if name.is_empty() || name.contains('/') || name.contains("..") {
        return Err("invalid plugin name".into());
    }
    let out = Command::new(guard_bin()?)
        .env("MONSTER_GUARD_HOME", guard_home())
        .args(["revoke", "command", name])
        .output()
        .map_err(|e| format!("spawn monster-guard: {e}"))?;
    if out.status.success() {
        Ok(String::from_utf8_lossy(&out.stdout).trim().to_string())
    } else {
        Err(String::from_utf8_lossy(&out.stderr).trim().to_string())
    }
}

/// Remove a plugin entirely: revoke its grant, then delete the grant file.
pub fn remove(name: &str) -> Result<(), String> {
    let _ = revoke(name); // best-effort revoke first
    let path = format!("{}/grants/{}.ucan", guard_home(), name);
    if std::path::Path::new(&path).exists() {
        std::fs::remove_file(&path).map_err(|e| format!("remove grant: {e}"))?;
    }
    Ok(())
}
